#!/usr/bin/perl
use warnings;
use strict;
use CAM::PDF;
use Text::ParseWords;

# Function to extract text from a PDF
sub extract_text {
    my ($pdf_file) = @_;
    my $pdf = CAM::PDF->new($pdf_file) or die "Cannot open $pdf_file: $CAM::PDF::errstr\n";

    my @pages = (0 .. $pdf->numPages() - 1);
    my @text;

    foreach my $page (@pages) {
        my $textpage = $pdf->getPageText($page);
        push @text, $textpage;
    }

    return join("\n", @text);
}

# Function to find dates in the extracted text
sub find_dates {
    my ($text) = @_;
    my @lines = split /\n/, $text;
    foreach my $line (@lines) {
        if ($line =~ /\b\d{1,2}[-/]\d{1,2}[-/]\d{2,4}\b/) {
            print "Found date: $line\n";
        }
    }
}

# Function to find authors in the extracted text
sub find_authors {
    my ($text) = @_;
    my @lines = split /\n/, $text;
    foreach my $line (@lines) {
        if ($line =~ /Author: (.+)/) {
            print "Found author: $1\n";
        }
    }
}

